local FitMode = UnityEngine.UI.ContentSizeFitter.FitMode
---@class LCityPeopleHud:LCityBase
local LCityPeopleHud = classX("LCityPeopleHud", LCityBase)
local typeOfFollowTransform = typeof(ProjectX.CFollowTransform)
function LCityPeopleHud:ctor()
    self._talkShowTime = GameTable.PeopleConfigRef.peopleTalkTime
    self._showSkillText = false
    self._peopleMgr = nil
    self._defaultCameraSize = 7.5
    self._curCameraSize = self._defaultCameraSize
    self._scaleRadio = 0.8 / (GameTable.BuildingConfigRef.cameraMaxRate - self._defaultCameraSize)
