    self._textInfo_text = FindChild(self._textInfo,"TextBg/Text"):GetComponent(typeof(ProjectX.CText))
    self._textInfo_bg = FindChild(self._textInfo,"TextBg")
    self._text_textRectTrans = self._textInfo_text:GetComponent(typeof(UnityEngine.RectTransform))
    self._text_textFitter =self._textInfo_text:GetComponent(ContentSizeFitter)
    self:HideIcon()
    self:HideChatText()
    self:HideQuestion()
end
function LCityPeopleHud:InitComponent()
    self._hudFollowTransformComponent = self._hudObj.gameObject:GetComponent(typeOfFollowTransform)
