end
function LCityPeopleHud:ResetParam()
    self._peopleRefId = 0;
    self._peopleData = nil
    self._peopleObject = nil;
    self._hudFollowTransformComponent = nil
    self._iconInfo = nil
    self._textInfo = nil
    self._textInfo_text = nil;
    self._hudObj = nil
    self._text_textFitter = nil
    self._peopleMgr = nil
    self.delayTimer = nil
    self._skillDelayTimer = nil
    self._randomTimeTimer = nil
    self:ResetTimeTimer()
    self:ResetSkillTimer()
    self:ResetNormalTimer()
end
function LCityPeopleHud:ResetTimeTimer()
    if(self._randomTimeTimer ~= nil)then
        MgrCenter.TimerMgr:StopTimer(timeKey.normal)
        MgrCenter.TimerMgr:RemoveTimer(self._randomTimeTimer)
        self._randomTimeTimer = nil
    end
end
function LCityPeopleHud:ResetNormalTimer()
    if(self.delayTimer ~= nil)then
        MgrCenter.TimerMgr:StopTimer(timeKey.normal)
        MgrCenter.TimerMgr:RemoveTimer(self.delayTimer)
        self.delayTimer = nil
    end
end
function LCityPeopleHud:ResetSkillTimer()
    if(self._skillDelayTimer ~= nil)then
        MgrCenter.TimerMgr:StopTimer(timeKey.skill)
        MgrCenter.TimerMgr:RemoveTimer(self._skillDelayTimer)
        self._skillDelayTimer = nil
    end
end
function LCityPeopleHud:ShowIcon()
    if(self._targetTrans == nil)then
        return
    end
    ShowObject(self._iconInfo.gameObject,true)
end
function LCityPeopleHud:HideIcon()
    if(self._targetTrans == nil)then
        return
    end
    ShowObject(self._iconInfo.gameObject,false)
end
--民心技能闲聊
function LCityPeopleHud:ShowSkillText(skillId)
    --self._showSkillText = true

    local isPeople = ModuleCenter.People:CheckIsResident(self._peopleRefId)
    if(isPeople)then
        --居民

        local peopleUnit = self._peopleMgr:GetPeopleUnit(self._peopleRefId)
        local curState = peopleUnit:GetFsm():GetCurState()._stateType
        --curState = CityPeopleFsmState.FindPath
        if(curState == CityPeopleFsmState.FindPath)then
            --正在寻路中
            --匹配的闲聊内容
            self:HideChatText()
            self:ResetNormalTimer()
            local talkList = {}
            for i, v in pairs(GameTable.PeopleTalkRef) do
                local type = string.split(v.type,"=")
                if(checknumber(type[1]) == 3 and checknumber(type[2]) == skillId)then
                    table.insert(talkList,v)
                end
            end
            local listCount = #talkList
            local text = ""
            if(listCount > 0)then
                if(listCount == 1)then
                    text = talkList[1].desc
                else
                    local random = math.random(1,listCount)
                    text = talkList[random].desc
                end
                self._showSkillText = true
                local min,max = 0.2,2.0
                local time =min+(max - min) * math.random()
                self:ResetTimeTimer()
                --随机个时间
               self._randomTimeTimer = MgrCenter.TimerMgr:DelayTime(function()
                    --设置文本
                   if(self._textInfo_text == nil)then
                       self:SetText(self._textInfo_text,I18nText(text))
                       --强制更新文本布局
                       LxUiHelper.TextNewLine(self._textInfo_text,self._text_textRectTrans,self._text_textFitter,272)

                       ShowObject(self._textInfo.gameObject,true)
                       PJXUtil.RebuildLayout(self._textInfo_text.transform);
                       PJXUtil.RebuildLayout(self._textInfo_bg.transform);
                       self:ResetTimeTimer()
                       self:ResetSkillTimer()
                       self._skillDelayTimer =MgrCenter.TimerMgr:DelayTime(function()
                           self:HideChatText()
                           self:ResetSkillTimer()
                           self._showSkillText = false
                       end,self,self._talkShowTime,false)
                   end

                end,timeKey.skill,time,false)
            end

        end
    end
end
--普通闲聊
function LCityPeopleHud:ShowChatText()
    if(self._targetTrans == nil)then
        return
    end
    if(ModuleCenter.Story:IsNewbieRunning())then
        self:HideChatText()
        return
    end
    if(self._showSkillText)then
        return
    end
    self:HideChatText()


    local talkList = nil
    if(ModuleCenter.People:CheckIsResident(self._peopleRefId))then
        --居民
        local timeState = CtrlCenter.City:GetCurTimeState()

        local peopleData = ModuleCenter.People:GetPeopleObj(self._peopleRefId);
        if(peopleData.building > 0)then
            if(timeState == 1 or timeState == 3)then
                return
            end
            --有工作
            --闲聊表里随机 2=buildId 的数据

            --判断是否生病去医院治疗，如果去医院治疗就不再随机工作的闲聊内容
            local inHospital = CtrlCenter.People:PeopleIsInHospital(self._peopleRefId)
            if(inHospital)then
                talkList = self:GetTalkConfigList(2,2006)
            else
                talkList = self:GetTalkConfigList(2,peopleData.building)
            end

        else
            --没工作
            local inHospital = CtrlCenter.People:PeopleIsInHospital(self._peopleRefId)
            if(inHospital)then
                talkList = self:GetTalkConfigList(2,2006)
            else
                --闲聊表里随机 2=0 的数据
                talkList = self:GetTalkConfigList(2,0)
            end

        end
    else
        --流民
        --闲聊表里随机type为 1=0 的数据
       talkList = self:GetTalkConfigList(1,0)
    end
    local length = table.nums(talkList)
    local index= math.random(1,length)
    local config = talkList[index]
    self:SetText(self._textInfo_text,I18nText(config.desc))

    --强制更新文本布局
    LxUiHelper.TextNewLine(self._textInfo_text,self._text_textRectTrans,self._text_textFitter,272)
    PJXUtil.RebuildLayout(self._textInfo_text.transform);
    PJXUtil.RebuildLayout(self._textInfo_bg.transform);
    ShowObject(self._textInfo.gameObject,true)

    self:ResetNormalTimer()
    self.delayTimer =MgrCenter.TimerMgr:DelayTime(function()
        self:HideChatText()
        self:ResetNormalTimer()
    end,timeKey.normal,self._talkShowTime,false)
end

---获取匹配的闲聊表的数据
function LCityPeopleHud:GetTalkConfigList(type1,type2)
    local res = {}
    for i, v in pairs(GameTable.PeopleTalkRef) do
        local type = v.type
        local types = string.split(type,"=")
        local t1 = checknumber(types[1])
        local t2 = checknumber(types[2])
        if(type1 == t1 and type2 == t2)then
            table.insert(res,v);
        end
    end
    return res;
end
function LCityPeopleHud:HideChatText()
    if IsNull(self._textInfo) then
        return
    end
    ShowObject(self._textInfo.gameObject,false)
end
function LCityPeopleHud:OnUpdate(deltaTime)
    if(CtrlCenter.City:GetCityView():GetCameraSize() == self._defaultCameraSize)then
        return
    end
    --if(CtrlCenter.City:GetCityView():GetCameraSize() == self._curCameraSize)then
    --    return
    --end
    self._curCameraSize = CtrlCenter.City:GetCityView():GetCameraSize()
    local scale = 1 -(self._curCameraSize - self._defaultCameraSize) * self._scaleRadio
    if(scale > 1)then
        scale = 1
    end
    if(self._iconInfo)then
        self._iconInfo.transform.localScale = Vector3(scale,scale,scale)
    end
    if(self._textInfo)then
        self._textInfo.transform.localScale = Vector3(scale,scale,scale)
    end
    if(self._questionInfo)then
        self._questionInfo.transform.localScale = Vector3(scale,scale,scale)
    end
    if(self._hudFollowTransformComponent)then
        local followY = (self._curCameraSize - self._defaultCameraSize) * self._followRadio
        self._hudFollowTransformComponent:SetOffset(Vector2(0,followY))
    end

end
return LCityPeopleHud